  IF to_regclass('public.doa_project_deliverables') IS NOT NULL AND EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'doa_project_deliverables' AND column_name = 'status'
  ) THEN
    UPDATE public.doa_project_deliverables SET status = CASE status WHEN 'en_revision' THEN 'in_review' WHEN 'pendiente' THEN 'pending' WHEN 'en_curso' THEN 'in_progress' WHEN 'completado' THEN 'completed' WHEN 'bloqueado' THEN 'blocked' WHEN 'no_aplica' THEN 'not_applicable' ELSE status END WHERE status IN ('en_revision', 'pendiente', 'en_curso', 'completado', 'bloqueado', 'no_aplica');
  END IF;
END $$;

