-- Recreate critical CHECK constraints with English values.
ALTER TABLE IF EXISTS public.doa_incoming_requests
  ADD CONSTRAINT doa_incoming_requests_status_check
  CHECK (status IN ('archived', 'awaiting_client_response', 'awaiting_form', 'define_scope', 'final_review', 'form_received', 'form_sent', 'new', 'project_opened', 'quote_accepted', 'quote_in_review', 'quote_rejected', 'quote_sent', 'request_received', 'scope_defined'));

ALTER TABLE IF EXISTS public.doa_projects
  ADD CONSTRAINT doa_projects_status_check
  CHECK (status IN ('active', 'approval', 'archived', 'canceled', 'closed', 'delivered', 'in_progress', 'in_review', 'new', 'paused', 'pending_cve_approval', 'pending_easa_approval', 'quote', 'review', 'saved_to_database'));

ALTER TABLE IF EXISTS public.doa_projects
  ADD CONSTRAINT doa_projects_execution_status_check
  CHECK (execution_status IS NULL OR execution_status IN ('project_opened', 'planning', 'in_execution', 'internal_review', 'ready_for_validation', 'in_validation', 'validated', 'returned_to_execution', 'preparing_delivery', 'delivered', 'client_confirmation', 'closed', 'project_archived'));

ALTER TABLE IF EXISTS public.doa_projects
  ADD CONSTRAINT doa_projects_current_phase_check
  CHECK (current_phase IS NULL OR current_phase IN ('execution', 'validation', 'delivery', 'closure'));

ALTER TABLE IF EXISTS public.doa_workflow_state_config
  ADD CONSTRAINT doa_workflow_state_config_scope_check
  CHECK (scope IN ('incoming_requests','quotation_board','project_board','project_execution'));

