  ) THEN
    UPDATE public.doa_workflow_state_config SET state_code = CASE state_code WHEN 'entrada_recibida' THEN 'request_received' WHEN 'formulario_enviado' THEN 'form_sent' WHEN 'formulario_recibido' THEN 'form_received' WHEN 'formulario_completado' THEN 'form_received' WHEN 'definir_alcance' THEN 'define_scope' WHEN 'esperando_respuesta_cliente' THEN 'awaiting_client_response' WHEN 'alcance_definido' THEN 'scope_defined' WHEN 'oferta_en_revision' THEN 'quote_in_review' WHEN 'oferta_enviada' THEN 'quote_sent' WHEN 'oferta_aceptada' THEN 'quote_accepted' WHEN 'oferta_rechazada' THEN 'quote_rejected' WHEN 'revision_final' THEN 'final_review' WHEN 'esperando_formulario' THEN 'awaiting_form' WHEN 'proyecto_abierto' THEN 'project_opened' WHEN 'nuevo' THEN 'new' WHEN 'archivado' THEN 'archived' WHEN 'entregado' THEN 'delivered' WHEN 'cerrado' THEN 'closed' WHEN 'planificacion' THEN 'planning' WHEN 'en_ejecucion' THEN 'in_execution' WHEN 'revision_interna' THEN 'internal_review' WHEN 'listo_para_validacion' THEN 'ready_for_validation' WHEN 'en_validacion' THEN 'in_validation' WHEN 'validado' THEN 'validated' WHEN 'devuelto_a_ejecucion' THEN 'returned_to_execution' WHEN 'preparando_entrega' THEN 'preparing_delivery' WHEN 'confirmacion_cliente' THEN 'client_confirmation' WHEN 'archivado_proyecto' THEN 'project_archived' WHEN 'en_progreso' THEN 'in_progress' WHEN 'revision' THEN 'review' WHEN 'aprobacion' THEN 'approval' WHEN 'oferta' THEN 'quote' WHEN 'activo' THEN 'active' WHEN 'en_revision' THEN 'in_review' WHEN 'pendiente_aprobacion_cve' THEN 'pending_cve_approval' WHEN 'pendiente_aprobacion_easa' THEN 'pending_easa_approval' WHEN 'en_pausa' THEN 'paused' WHEN 'cancelado' THEN 'canceled' WHEN 'guardado_en_base_de_datos' THEN 'saved_to_database' ELSE state_code END WHERE state_code IN ('entrada_recibida', 'formulario_enviado', 'formulario_recibido', 'formulario_completado', 'definir_alcance', 'esperando_respuesta_cliente', 'alcance_definido', 'oferta_en_revision', 'oferta_enviada', 'oferta_aceptada', 'oferta_rechazada', 'revision_final', 'esperando_formulario', 'proyecto_abierto', 'nuevo', 'archivado', 'entregado', 'cerrado', 'planificacion', 'en_ejecucion', 'revision_interna', 'listo_para_validacion', 'en_validacion', 'validado', 'devuelto_a_ejecucion', 'preparando_entrega', 'confirmacion_cliente', 'archivado_proyecto', 'en_progreso', 'revision', 'aprobacion', 'oferta', 'activo', 'en_revision', 'pendiente_aprobacion_cve', 'pendiente_aprobacion_easa', 'en_pausa', 'cancelado', 'guardado_en_base_de_datos');
  END IF;
END $$;

DO $$
BEGIN
  IF to_regclass('public.doa_workflow_state_config') IS NOT NULL AND EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'doa_workflow_state_config' AND column_name = 'scope'
  ) THEN
    UPDATE public.doa_workflow_state_config SET scope = CASE scope WHEN 'incoming_queries' THEN 'incoming_requests' ELSE scope END WHERE scope IN ('incoming_queries');
  END IF;
END $$;

COMMIT;
